import { Chart } from '@antv/g2';

const data = [];
for (let x = 0; x < 12; x++) {
  for (let y = 0; y < 24; y++) {
    data.push({
      hour: x,
      day: y,
      intensity: Math.round(50 + 50 * Math.sin(x / 2) * Math.cos(y / 3)),
    });
  }
}

const chart = new Chart({ container: 'container', autoFit: true });
chart.options({
  type: 'heatmap',
  data,
  encode: { x: 'hour', y: 'day', color: 'intensity' },
  style: { stroke: '#eee', lineWidth: 1 },
  axis: { x: { title: '小时' }, y: { title: '星期' } },
});
chart.render();

