import { Chart } from '@antv/g2';

const chart = new Chart({
  container: 'container',
  width: 640,
  height: 400,
});

const data = [
  { text: 'A', value: 12000 },
  { text: 'B', value: 9800 },
  { text: 'C', value: 6789 },
  { text: 'D', value: 4569 },
];

// 计算转换率
const dataWithRate = data.map((d, i) => ({
  ...d,
  rate: i === 0 ? '100%' : `${((d.value / data[i - 1].value) * 100).toFixed(1)}%`,
  totalRate: i === 0 ? '100%' : `${((d.value / data[0].value) * 100).toFixed(1)}%`,
}));

// 计算每段的中心位置（用于连接线）
const maxValue = data[0].value;
const centerData = data.map((d, i) => ({
  x: i,
  y: 0, // 中心线
  text: d.text,
  value: d.value,
}));

chart.options({
  type: 'view',
  data: dataWithRate,
  axis: false,
  legend: false,
  scale: {
    x: { type: 'band', padding: 0.2 },
    y: { domain: [-maxValue, maxValue] },
  },
  children: [
    // 左侧漏斗（负值）
    {
      type: 'interval',
      encode: {
        x: 'text',
        y: (d) => -d.value,
        color: 'text',
        shape: 'funnel',
      },
      transform: [{ type: 'symmetryY' }],
      coordinate: { transform: [{ type: 'transpose' }] },
      style: { stroke: '#fff', lineWidth: 1 },
    },
    // 右侧漏斗（正值）
    {
      type: 'interval',
      encode: {
        x: 'text',
        y: 'value',
        color: 'text',
        shape: 'funnel',
      },
      transform: [{ type: 'symmetryY' }],
      coordinate: { transform: [{ type: 'transpose' }] },
      style: { stroke: '#fff', lineWidth: 1 },
    },
    // 中间标签（阶段名称和数值）
    {
      type: 'text',
      encode: {
        x: 'text',
        y: 0,
        text: (d) => `${d.text}\n${d.value.toLocaleString()}`,
      },
      style: {
        textAlign: 'center',
        textBaseline: 'middle',
        fill: '#333',
        fontSize: 12,
        fontWeight: 'bold',
      },
    },
    // 右侧转换率标注（从第二阶段开始）
    {
      type: 'text',
      data: dataWithRate.slice(1),
      encode: {
        x: 'text',
        y: (d) => d.value / 2,
        text: (d) => `转化率 ${d.rate}`,
      },
      style: {
        textAlign: 'left',
        dx: 10,
        fill: '#52c41a',
        fontSize: 11,
      },
    },
    // 左侧总转换率标注
    {
      type: 'text',
      encode: {
        x: 'text',
        y: (d) => -d.value / 2,
        text: (d) => (d.text === 'A' ? '总转化率' : `占A: ${d.totalRate}`),
      },
      style: {
        textAlign: 'right',
        dx: -10,
        fill: '#1890ff',
        fontSize: 11,
      },
    },
    // 连接线（从A到D的中心线）
    {
      type: 'line',
      data: centerData,
      encode: {
        x: 'text',
        y: 'y',
      },
      coordinate: { transform: [{ type: 'transpose' }] },
      style: {
        stroke: '#999',
        lineWidth: 1,
        lineDash: [4, 4],
        opacity: 0.6,
      },
    },
  ],
});

chart.render();

