// 生成 300 个模拟数据点（6个分组，每组50个点）
const generateData = () => {
  const groups = ['G1', 'G2', 'G3', 'G4', 'G5', 'G6'];
  const data = [];
  for (let i = 0; i < 300; i++) {
    const group = groups[i % 6];
    // 为每个分组生成不同范围的 y 值分布
    const baseY = 30 + (i % 6) * 10;
    const y = baseY + Math.random() * 20 + Math.sin(i * 0.1) * 5;
    const radius = 3 + Math.random() * 8; // radius 范围 3-11
    data.push({
      x: group,
      y: y,
      radius: radius,
      id: i
    });
  }
  return data;
};

