import { Chart } from '@antv/g2';

const chart = new Chart({
  container: 'container',
  width: 640,
  height: 300,
  paddingLeft: 80,
});

// 原始数据
const rawData = [
  { campaign: '618大促', ctr: 5.2, targetCtr: 6, maxCtr: 10, bands: [4, 3, 3] },
  { campaign: '双11', ctr: 7.8, targetCtr: 7, maxCtr: 10, bands: [4, 3, 3] },
  { campaign: '春节场', ctr: 3.9, targetCtr: 5.5, maxCtr: 10, bands: [4, 3, 3] },
];

// 转换数据：生成背景分级色带数据（堆叠）
const bandData = [];
const measureData = [];
const targetData = [];

rawData.forEach((d) => {
  let start = 0;
  const levels = ['差', '良', '优'];
  const colors = ['#E4E4E4', '#B8B8B8', '#8C8C8C'];

  d.bands.forEach((band, i) => {
    bandData.push({
      campaign: d.campaign,
      level: levels[i],
      start: start,
      end: start + band,
      color: colors[i],
    });
    start += band;
  });

  // 实际点击率数据
  measureData.push({
    campaign: d.campaign,
    ctr: d.ctr,
  });

  // 目标点击率数据
  targetData.push({
    campaign: d.campaign,
    targetCtr: d.targetCtr,
  });
});

chart.options({
  type: 'view',
  coordinate: { transform: [{ type: 'transpose' }] }, // 水平条形图
  children: [
    // 背景分级色带（堆叠条形）
    {
      type: 'interval',
      data: bandData,
