      style: { maxWidth: 20 },
      labels: [{ text: 'ctr', formatter: (d) => `${d.ctr}%` }],
    },
    // 目标点击率标记（线形）
    {
      type: 'point',
      data: targetData,
      encode: {
        x: 'campaign',
        y: 'targetCtr',
        shape: 'line',
        color: () => '#E8684A',
        size: 12,
      },
      style: { lineWidth: 3 },
      labels: [{ text: 'targetCtr', formatter: (d) => `目标: ${d.targetCtr}%`, dy: -15 }],
    },
