const chart = new Chart({
  container: 'container',
  width: 640,
  height: 480,
});

const data = [
  { level: '浏览商品', uv: 20000 },
  { level: '加入购物车', uv: 8000, highlight: true },
  { level: '结算页', uv: 3000, highlight: true },
  { level: '支付成功', uv: 1200 },
  { level: '复购', uv: 400 },
];

// 计算转化率和标签内容
const dataWithRate = data.map((d, i) => {
  const prev = i > 0 ? data[i - 1].uv : d.uv;
  const rate = i === 0 ? 100 : ((d.uv / prev) * 100).toFixed(1);
  return {
    ...d,
    rate: `${rate}%`,
    // 高亮项显示转化率和警告符号，非高亮项显示UV值
    labelText: d.highlight ? `⚠️ ${d.level}：转化率 ${rate}%` : `${d.level}：${d.uv.toLocaleString()}`,
