      data.push({
        segment: `${month} ${section}`,
        time: `${month}-${day.toString().padStart(2,'0')}`,
        aqi: Math.max(10, Math.min(150, baseAQI + sectionAdjust + noise)),
        section
      });
    }
  });
});

