// 生成模拟的年度空气质量数据（365天，每天昼夜两个数据点）
const generateData = () => {
  const data = [];
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const daysInMonth = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

  let dayIndex = 0;

  months.forEach((month, monthIdx) => {
    for (let day = 1; day <= daysInMonth[monthIdx]; day++) {
      // 模拟 AQI 数据：冬季污染较重，夏季较好，白天略高于夜间
      const seasonFactor = 1 + 0.4 * Math.cos((monthIdx / 12) * Math.PI * 2 + Math.PI); // 冬季高
      const randomFactor = () => 0.7 + Math.random() * 0.6;

      // 白天 AQI
      const dayAqi = Math.round(45 * seasonFactor * randomFactor() + 20);
      // 夜间 AQI（略低）
      const nightAqi = Math.round(35 * seasonFactor * randomFactor() + 15);

      data.push({
        segment: `${month} Day`,
        time: `${month}-${String(day).padStart(2, '0')}`,
        aqi: dayAqi,
        section: 'Day',
