import { Chart } from '@antv/g2';

// 生成180个时间点的心率监测数据
const data = Array.from({ length: 180 }, (_, i) => {
  const angle = i * 0.2; // 角度递增
  const radius = 10 + i * 0.3; // 半径递增，形成螺旋向外
  // 心率随角度呈正弦波动并叠加随机噪声
  const baseBpm = i < 90 ? 70 : 110; // 静息状态基础心率70，运动状态基础心率110
  const sineWave = Math.sin(angle * 2) * 10; // 正弦波动
  const noise = (Math.random() - 0.5) * 15; // 随机噪声
  const bpm = baseBpm + sineWave + noise;
  const type = i < 90 ? '静息' : '运动';
  return {
    angle,
    radius,
    bpm: Math.round(bpm * 10) / 10, // 保留一位小数
    type,
  };
});

