  container: 'container',
  autoFit: true,
  height: 400,
});

chart.options({
  type: 'density',
  data: {
    type: 'fetch',
    value: 'https://assets.antv.antgroup.com/g2/species.json',
    transform: [
      {
        type: 'kde',
        field: 'y',              // 对数值字段 y 进行核密度估计
